SELECT 
FROM tb_config_word t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.type = #{type}


    AND t.reference_id = #{referenceId}


    AND t.device_code = #{deviceCode}


    AND t.software_pn = #{softwarePn}


    AND t.config_word_version = #{configWordVersion}


    AND t.start_byte = #{startByte}


    AND t.start_bit = #{startBit}


    AND t.config_word_value = #{configWordValue}


    AND t.depend_device = #{dependDevice}


    AND t.depend_device_software_pn = #{dependDeviceSoftwarePn}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC

